B.a6U=new A.n(B.h,["\ud83d\udede Flat Tyre","\ud83d\udede \u092b\u094d\u0932\u0948\u091f \u091f\u093e\u092f\u0930","\ud83d\udede \u0c2b\u0c4d\u0c32\u0c3e\u0c1f\u0c4d \u0c1f\u0c48\u0c30\u0c4d","\ud83d\udede \u0ba4\u0b9f\u0bcd\u0b9f\u0bc8\u0baf\u0bbe\u0ba9 \u0b9f\u0baf\u0bb0\u0bcd"],t.w)
